#include <iostream>

int main()
{
    int rows{};
    int cols{};
    std::cin >> rows >> cols;

    int** matrix{ new int*[rows] };
    for (int r{ 0 }; r < rows; ++r)
        matrix[r] = new int[cols]{};

    for (int r{ 0 }; r < rows; ++r)
        for (int c{ 0 }; c < cols; ++c)
            std::cin >> matrix[r][c];

    for (int r{ 0 }; r < rows; ++r)
    {
        for (int c{ 0 }; c < cols; ++c)
        {
            if (c > 0)
                std::cout << ' ';
            std::cout << matrix[r][c];
        }
        std::cout << '\n';
    }

    for (int r{ 0 }; r < rows; ++r)
        delete[] matrix[r];
    delete[] matrix;

    return 0;
}

